#include <stdio.h>
#include <string.h>

int countSubsequence(char *s, char *sub) {
    int count = 0;
    int len = strlen(s);
    int subLen = strlen(sub);
    for (int i = 0; i < (1 << len); i++) {
        int j = 0;
        int k = 0;
        for (int bit = 0; bit < len; bit++) {
            if ((i & (1 << bit)) != 0) {
                if (s[bit] == sub[j]) {
                    j++;
                }
            }
        }
        if (j == subLen) {
            count++;
        }
    }
    return count;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[5005];
        scanf("%s", s);
        int len = strlen(s);
        int found = 0;
        for (int i = 0; i < (1 << len); i++) {
            char sub[5005];
            int j = 0;
            for (int bit = 0; bit < len; bit++) {
                if ((i & (1 << bit)) != 0) {
                    sub[j++] = s[bit];
                }
            }
            sub[j] = '\0';
            if (countSubsequence(s, sub) == 2) {
                printf("%s\n", sub);
                found = 1;
                break;
            }
        }
        if (!found) {
            printf("-1\n");
        }
    }
    return 0;
}

