import java.util.Scanner;
public class Main {
    public static int countSubsequence(String s, String sub) {
        int count = 0;
        int len = s.length();
        int subLen = sub.length();
        for (int i = 0; i < (1 << len); i++) {
            int j = 0;
            int k = 0;
            for (int bit = 0; bit < len; bit++) {
                if ((i & (1 << bit)) != 0) {
                    if (s.charAt(bit) == sub.charAt(j)) {
                        j++;
                    }
                }
            }
            if (j == subLen) {
                count++;
            }
        }
        return count;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            String s = sc.next();
            int len = s.length();
            int found = 0;
            for (int i = 0; i < (1 << len); i++) {
                StringBuilder sub = new StringBuilder();
                for (int bit = 0; bit < len; bit++) {
                    if ((i & (1 << bit)) != 0) {
                        sub.append(s.charAt(bit));
                    }
                }
                if (countSubsequence(s, sub.toString()) == 2) {
                    System.out.println(sub.toString());
                    found = 1;
                    break;
                }
            }
            if (found == 0) {
                System.out.println(-1);
            }
        }
    }
}

